"""
This module defines the Board class that represents the checkers board.
"""

class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.init_board()

    def init_board(self):
        # Initialize the board with pieces
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece('black', (row, col))
        for row in range(5, 8):
            for col in range((row - 4) % 2, 8, 2):
                self.board[row][col] = Piece('white', (row, col))

    def print_board(self):
        import termcolor
        board_str = ""
        for row in self.board:
            board_str += "|"
            for piece in row:
                if piece is None:
                    board_str += "   |"
                else:
                    color = "red" if piece.color == 'black' else "yellow"
                    board_str += termcolor.colored(f"{piece.symbol}", color) + " |"
            board_str += "\n"
        print(board_str)
```

