"""
This module defines the Player class that represents a player in the game.
"""

class Player:
    def __init__(self, color):
        self.color = color
        self.captures = []

    def move(self, board, start, end):
        piece = board.board[start[0]][start[1]]
        if piece is not None and piece.color == self.color:
            # Move the piece
            board.board[start[0]][start[1]] = None
            board.board[end[0]][end[1]] = piece
            piece.position = end

            # Check for capture
            if abs(end[0] - start[0]) == 2:
                board.capture_piece(start, end)
                self.captures.append(end)

    def has_valid_moves(self, board):
        for row in range(8):
            for col in range(8):
                piece = board.board[row][col]
                if piece is not None and piece.color == self.color:
                    if self.valid_moves(board, (row, col)):
                        return True
        return False

    def valid_moves(self, board, position):
        row, col = position
        moves = []
        directions = [(-1, -1), (-1, 1), (1, -1), (1, 1)]
        for dr, dc in directions:
            if self.color == 'black' and row >= 5 or self.color == 'white' and row <= 2:
                moves.append((row + 2 * dr, col + 2 * dc))
            else:
                moves.append((row + dr, col + dc))
        valid_moves = []
        for move in moves:
            if 0 <= move[0] < 8 and 0 <= move[1] < 8 and board.board[move[0]][move[1]] is None:
                valid_moves.append(move)
        return valid_moves
```

