"""
This module defines the Game class that manages the game state.
"""

from player import Player, Board

class Game:
    def __init__(self):
        self.board = Board()
        self.players = [Player('black'), Player('white')]
        self.current_player_index = 0

    def switch_turn(self):
        self.current_player_index = 1 - self.current_player_index

    def play_move(self, start, end):
        current_player = self.players[self.current_player_index]
        if current_player.move(self.board, start, end):
            self.switch_turn()

    def print_board(self):
        self.board.print_board()
```

